// Calculate weekly analytics
const jobData = $input.first().json;
const contentData = $input.all()[1].json;
const networkingData = $input.all()[2].json;

// Get current week date range
const now = new Date();
const weekStart = new Date(now.setDate(now.getDate() - now.getDay()));
const weekEnd = new Date(now.setDate(now.getDate() - now.getDay() + 6));

// Filter data for current week
const thisWeekJobs = jobData.filter(job => {
  const jobDate = new Date(job['Date Applied']);
  return jobDate >= weekStart && jobDate <= weekEnd;
});

const thisWeekContent = contentData.filter(content => {
  const contentDate = new Date(content['Date']);
  return contentDate >= weekStart && contentDate <= weekEnd;
});

const thisWeekNetworking = networkingData.filter(network => {
  const networkDate = new Date(network['Date']);
  return networkDate >= weekStart && networkDate <= weekEnd;
});

// Calculate metrics
const analytics = {
  week_ending: weekEnd.toISOString().split('T')[0],
  jobs_applied: thisWeekJobs.length,
  job_responses: thisWeekJobs.filter(job => job.Status === 'Response Received').length,
  content_published: thisWeekContent.length,
  total_engagement: thisWeekContent.reduce((sum, content) => sum + (parseInt(content.Engagement) || 0), 0),
  new_connections: thisWeekNetworking.filter(network => network.Type === 'Connection').length,
  messages_sent: thisWeekNetworking.filter(network => network.Type === 'Message').length,
  response_rate: thisWeekJobs.length > 0 ? (thisWeekJobs.filter(job => job.Status === 'Response Received').length / thisWeekJobs.length * 100).toFixed(1) + '%' : '0%',
  avg_engagement: thisWeekContent.length > 0 ? (thisWeekContent.reduce((sum, content) => sum + (parseInt(content.Engagement) || 0), 0) / thisWeekContent.length).toFixed(1) : '0'
};

return analytics;
